const express = require('express');
const axios = require('axios');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

const OIDC_ISSUER = 'https://your-oidc-provider.com';
const CLIENT_ID = 'your-client-id';
const CLIENT_SECRET = 'your-client-secret';

app.get('/login', (req, res) => {
  const authUrl = `${OIDC_ISSUER}/authorize?response_type=code&client_id=${CLIENT_ID}&redirect_uri=http://localhost:3000/callback&scope=openid email profile`;
  res.redirect(authUrl);
});

app.get('/callback', async (req, res) => {
  const { code } = req.query;

  try {
    const tokenResponse = await axios.post(`${OIDC_ISSUER}/token`, null, {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      params: {
        grant_type: 'authorization_code',
        client_id: CLIENT_ID,
        client_secret: CLIENT_SECRET,
        code,
        redirect_uri: 'http://localhost:3000/callback',
      },
    });

    const { id_token } = tokenResponse.data;

    const decodedToken = jwt.decode(id_token, { complete: true });
    if (!decodedToken || !decodedToken.payload) {
      return res.status(401).send('Invalid ID Token');
    }

    const { sub, email, name } = decodedToken.payload;
    req.session.user = { sub, email, name };
    res.send(`Logged in as ${name}`);
  } catch (error) {
    console.error(error);
    res.status(500).send('Authentication failed');
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});